'use client';

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { createClient } from '@/lib/supabase/client';
import { useUserProfile } from './useUserProfile';
import { toast } from '@/hooks/use-toast';
import {
    FinancialBudget,
    FinancialBudgetInsert,
    FinancialBudgetUpdate,
    BudgetWithSpent,
} from '@/types/financial';

export function useFinancialBudgets() {
    const supabase = createClient();
    const queryClient = useQueryClient();
    const { user, profile, isAdmin } = useUserProfile();

    // Query for budgets with spent calculations
    const {
        data: budgets = [],
        isLoading,
        error,
        refetch,
    } = useQuery({
        queryKey: ['financial-budgets', user?.id, profile?.role],
        queryFn: async (): Promise<BudgetWithSpent[]> => {
            if (!user?.id) return [];

            const isAdminOrDono = isAdmin;

            // Fetch budgets with category
            let query = supabase
                .from('financial_budgets')
                .select(`
                    *,
                    category:financial_categories(id, name, color)
                `)
                .order('created_at', { ascending: false });

            if (!isAdminOrDono) {
                query = query.eq('user_id', user.id);
            }

            const { data: budgetsData, error: budgetsError } = await query as {
                data: Array<FinancialBudget & { category: { id: string; name: string; color: string | null } | null }> | null;
                error: Error | null;
            };

            if (budgetsError) throw budgetsError;

            // For each budget, calculate spent amount
            const budgetsWithSpent: BudgetWithSpent[] = await Promise.all(
                (budgetsData || []).map(async (budget) => {
                    // Get sum of expense transactions for the category in the period
                    const { data: transactionsData } = await supabase
                        .from('financial_transactions')
                        .select('amount')
                        .eq('category_id', budget.category_id)
                        .eq('type', 'saida')
                        .gte('transaction_date', budget.period_start)
                        .lte('transaction_date', budget.period_end) as {
                            data: { amount: number | null }[] | null;
                        };

                    const spent = transactionsData?.reduce((sum, t) => sum + (t.amount || 0), 0) || 0;
                    const percentage_used = budget.amount > 0 ? (spent / budget.amount) * 100 : 0;
                    const remaining = budget.amount - spent;

                    return {
                        ...budget,
                        spent,
                        category_name: budget.category?.name || 'Sem categoria',
                        category_color: budget.category?.color || '#3b82f6',
                        percentage_used,
                        remaining,
                    };
                })
            );

            return budgetsWithSpent;
        },
        enabled: !!user?.id,
    });

    // Create budget mutation
    const createBudget = useMutation({
        mutationFn: async (budget: Omit<FinancialBudgetInsert, 'user_id' | 'organization_id'>) => {
            if (!user?.id) throw new Error('Usuário não autenticado');

            const insertData: FinancialBudgetInsert = {
                ...budget,
                user_id: user.id,
                organization_id: profile?.organization_id || null,
            };

            const { data, error } = await supabase
                .from('financial_budgets')
                .insert(insertData as never)
                .select()
                .single();

            if (error) throw error;
            return data as FinancialBudget;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['financial-budgets'] });
            toast({
                title: 'Orçamento criado',
                description: 'Orçamento criado com sucesso!',
            });
        },
        onError: (error: Error) => {
            console.error('Error creating budget:', error);
            toast({
                variant: 'destructive',
                title: 'Erro ao criar orçamento',
                description: error.message,
            });
        },
    });

    // Update budget mutation
    const updateBudget = useMutation({
        mutationFn: async ({ id, updates }: { id: string; updates: FinancialBudgetUpdate }) => {
            if (!user?.id) throw new Error('Usuário não autenticado');

            const isAdminOrDono = isAdmin;

            let query = supabase
                .from('financial_budgets')
                .update(updates as never)
                .eq('id', id);

            if (!isAdminOrDono) {
                query = query.eq('user_id', user.id);
            }

            const { data, error } = await query.select().single();

            if (error) throw error;
            return data as FinancialBudget;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['financial-budgets'] });
            toast({
                title: 'Orçamento atualizado',
                description: 'Orçamento atualizado com sucesso!',
            });
        },
        onError: (error: Error) => {
            console.error('Error updating budget:', error);
            toast({
                variant: 'destructive',
                title: 'Erro ao atualizar orçamento',
                description: error.message,
            });
        },
    });

    // Delete budget mutation
    const deleteBudget = useMutation({
        mutationFn: async (id: string) => {
            if (!user?.id) throw new Error('Usuário não autenticado');

            const isAdminOrDono = isAdmin;

            let query = supabase
                .from('financial_budgets')
                .delete()
                .eq('id', id);

            if (!isAdminOrDono) {
                query = query.eq('user_id', user.id);
            }

            const { error } = await query;

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: ['financial-budgets'] });
            toast({
                title: 'Orçamento removido',
                description: 'Orçamento removido com sucesso!',
            });
        },
        onError: (error: Error) => {
            console.error('Error deleting budget:', error);
            toast({
                variant: 'destructive',
                title: 'Erro ao remover orçamento',
                description: error.message,
            });
        },
    });

    // Calculate totals
    const totalBudget = budgets.reduce((sum, b) => sum + (b.amount || 0), 0);
    const totalSpent = budgets.reduce((sum, b) => sum + (b.spent || 0), 0);
    const totalRemaining = totalBudget - totalSpent;
    const overallPercentage = totalBudget > 0 ? (totalSpent / totalBudget) * 100 : 0;

    // Filter budgets by status
    const activeBudgets = budgets.filter((b) => b.status === 'active');
    const exceededBudgets = budgets.filter((b) => b.percentage_used >= 100);
    const warningBudgets = budgets.filter((b) => b.percentage_used >= 80 && b.percentage_used < 100);

    return {
        budgets,
        activeBudgets,
        exceededBudgets,
        warningBudgets,
        isLoading,
        error,
        refetch,
        totalBudget,
        totalSpent,
        totalRemaining,
        overallPercentage,
        createBudget,
        updateBudget,
        deleteBudget,
        isCreating: createBudget.isPending,
        isUpdating: updateBudget.isPending,
        isDeleting: deleteBudget.isPending,
    };
}
